// Shape-agnostic reader for the Basic LLM Chain ('Generate Launch Content').
// The Basic LLM Chain can hand us the data in EITHER of two shapes, depending
// on the model's Response Format:
//   PATH A (already-parsed): because OpenAI Chat Model has Response Format =
//     JSON, the chain auto-parses the model's JSON and exposes the 5 content
//     keys DIRECTLY at the top level of item.json. There is no `text` field.
//   PATH B (text-to-parse): the chain returns the raw string under `text`
//     (or `output` / `response`), which we must JSON.parse ourselves.
// This code handles both without assuming which one occurred.
const item = $input.first();
const data = item.json || {};
const required = ['blog_intro', 'linkedin_post', 'x_post', 'instagram_caption', 'launch_email'];

// Coerce any value to a string so downstream nodes always get clean text,
// even if the model returned a number, null, or an object for a field.
function asString(v) { return (v === undefined || v === null) ? '' : String(v); }

let parsed;
let pathTaken;

// PATH A — the 5 keys are already present at the top level: use them directly.
if (required.some(function (key) { return key in data; })) {
  parsed = data;
  pathTaken = 'already-parsed';
} else {
  // PATH B — fall back to a raw text field and parse it ourselves.
  const raw = data.text ?? data.output ?? data.response;
  if (raw === undefined || raw === null || raw === '') {
    throw new Error(
      'Could not find content. No top-level content keys and no text/output/response field. ' +
      'Received keys: ' + JSON.stringify(Object.keys(data))
    );
  }
  // The model may wrap JSON in markdown code fences (```json ... ```). Strip them.
  let cleaned = String(raw).trim()
    .replace(/^```(?:json)?\s*/i, '')  // opening fence
    .replace(/\s*```$/i, '')           // closing fence
    .trim();
  try {
    parsed = JSON.parse(cleaned);
  } catch (e) {
    throw new Error(
      'LLM did not return valid JSON. Parse error: ' + e.message +
      '\n--- Raw text received ---\n' + String(raw)
    );
  }
  pathTaken = 'text-to-parse';
}

// Only fail if a key is genuinely ABSENT. A present-but-empty value is fine.
const missing = required.filter(function (key) { return !(key in parsed); });
if (missing.length > 0) {
  throw new Error(
    'Content is missing required key(s): ' + missing.join(', ') +
    ' (path: ' + pathTaken + '). Received keys: ' + JSON.stringify(Object.keys(parsed))
  );
}

return [{
  json: {
    blog_intro: asString(parsed.blog_intro),
    linkedin_post: asString(parsed.linkedin_post),
    x_post: asString(parsed.x_post),
    instagram_caption: asString(parsed.instagram_caption),
    launch_email: asString(parsed.launch_email)
  }
}];
